import 'package:freezed_annotation/freezed_annotation.dart';

part 'share_content.freezed.dart';

/// Represents shareable content generated by the share feature.
@freezed
sealed class ShareContent with _$ShareContent {
  const factory ShareContent.screenshot({
    required String filePath,
    required String surahName,
    required int pageNumber,
  }) = ShareScreenshot;

  const factory ShareContent.audioClip({
    required String filePath,
    required String surahName,
    required int fromAyah,
    required int toAyah,
    required String reciterName,
  }) = ShareAudioClip;

  const factory ShareContent.reel({
    required String filePath,
    required String surahName,
    required int fromAyah,
    required int toAyah,
    required String reciterName,
  }) = ShareReel;

  const factory ShareContent.text({
    @Default('') String filePath,
    @Default('') String surahName,
    required String text,
  }) = ShareText;
}
